// Tenacity 5.1 - AutoRespawn trigger on health <= 0
if (event.getPacket() instanceof S06PacketUpdateHealth) {
  S06PacketUpdateHealth s06 =
    (S06PacketUpdateHealth) event.getPacket();
  if (s06.getHealth() <= 0) { autoRespawn(); }
  if (s06.getHealth() < threshold) { autoPot(); }
}

// Gugustus - GodMode (prevent death)
if (event.getPacket() instanceof S06PacketUpdateHealth) {
  S06PacketUpdateHealth s06 =
    (S06PacketUpdateHealth) event.getPacket();
  if (s06.getHealth() <= 0) { event.setCancelled(true); }
}
